import * as formatError from 'format-error';
//import stackTrace from 'stack-trace';
import * as util from 'util';
import * as Minilog from 'minilog';

export enum Level {
    debug = <any>'debug',
    info = <any>'info',
    warn = <any>'warn',
    error = <any>'error'
};

export function FormatHelper(args:any[]):string {
    const formatObj = (obj) => {
        let text:string = util.inspect(obj);
        if (obj && obj instanceof Error && obj.stack) {
            //text += '\n' + util.inspect(stackTrace.parse(obj));
            text += '\n' + formatError.format(obj);
        }
        return text;
    };
    const text:string = args.map( (item) => {
        return (typeof item === 'string' ? item : formatObj(item));
    }).join(' ').trim();

    return text;
}


function logUncaught(minilog:Minilog, err:Error)
{
    minilog.error('Uncaught', err);
    const msg:string = FormatHelper([err]);  // hopefully add useful stack traces to uncaught exceptions
    minilog.error(msg);

    // // flush or close logging files? FIXME
    // Minilog.end()  // or:
    // Object.keys(loggingToFiles).forEach( (filename) => {
    //     let pipe = loggingToFiles[filename];
    //     //Minilog.unpipe(pipe);  // hoping unhooking pipe will flush file (nope!)
    //     //Minilog.pipe(pipe);  // hoping i can then reattach pipe
    // });

    throw err;  // rethrow the error, which amazingly doesn't cause a loop
}


function logUnhandled(minilog:Minilog, reason:string|Error, p:any) {
    minilog.log('Unhandled Rejection at: Promise ', p, ' reason: ', reason);
    if (reason instanceof Error) {
        minilog.log(reason.stack);
    }

    // we should probably do all the process exit logic that logUncaughtException does FIXME
}


let handlersInstalledOnce:boolean = false;
let uncaughtCallback:Function;
let unhandledCallback:Function;
export function handleUncaughtAndUnhandled() {
    if (!handlersInstalledOnce && (typeof process === 'object')) {  // only when running under node
        const minilog:Minilog = Minilog('[uncaught]');
        // log uncaughtExceptions
        uncaughtCallback = (err) => { logUncaught(minilog, err); };
        unhandledCallback = (reason, p) => { logUnhandled(minilog, reason, p); };
        
        process.on('uncaughtException', uncaughtCallback);
        // log any unhandled, otherwise silent, promise exceptions too
        process.on('unhandledRejection', unhandledCallback);

        handlersInstalledOnce = true;
    }
}


export function stopHandlingUncaughtAndUnhandled() {
    if (handlersInstalledOnce) {
        process.removeListener('uncaughtException', uncaughtCallback);
        process.removeListener('unhandledRejection', unhandledCallback);
        handlersInstalledOnce = false;
    }
}
