import path = require('path');
import * as Minilog from 'minilog';  // the one true minilog instance

import {handleUncaughtAndUnhandled, stopHandlingUncaughtAndUnhandled} from './utils';
import {Level} from './utils';
import FileBackend from './FileBackend';
import SyslogBackend from './SyslogBackend';

/** 
 * JiboLog class - centralized logging facility
 * @class JiboLog
 * @param {String} [name='[unknown module]'] The log name.
 */
class JiboLog {

    /**
     * Current version of the library.
     * @name JiboLog.version
     * @type String
     */
    public static version:string = '2.4.0';

    /**
     * The syslog backend plugin for Minilog.
     * @name JiboLog.syslogBackend
     * @type SyslogBackend
     */
    public static syslogBackend:SyslogBackend;

    private _name:string;
    private _minilog:Minilog;
    private _defaultDir:string;
    private _handleAll:boolean;
    private _minLevel:Level;
    private _enabled:boolean;

    constructor(name:string='[unknown module]') {
        this.name = name;
        this.enabled = true;
        this.handleAll = false;  // off by default now
        this.minLevel = Level.info;
        this._minilog = Minilog(this._name);
    }

    /**
     * General log message, alias for `debug`.
     * @method JiboLog#log
     * @param {*} ..args Arguments for logging
     * @return {JiboLog} Instance of log for chaining.
     */
    log(): JiboLog {
        return this.debug.apply(this, arguments);
    }

    /**
     * Debug log message, lowest level message.
     * @method JiboLog#debug
     * @param {*} ..args Arguments for logging
     * @return {JiboLog} Instance of log for chaining.
     */
    debug(): JiboLog {
        if (!this._enabled || !this._gt(Level.debug)) {
            return this;
        }
        this._minilog.debug.apply(Minilog, arguments);
        return this;
    }

    /**
     * Info log message.
     * @method JiboLog#info
     * @param {*} ..args Arguments for logging
     * @return {JiboLog} Instance of log for chaining.
     */
    info(): JiboLog {
        if (!this._enabled || !this._gt(Level.info)) {
            return this;
        }
        this._minilog.info.apply(Minilog, arguments);
        return this;
    }

    /**
     * Warrning log message.
     * @method JiboLog#warn
     * @param {*} ..args Arguments for logging
     * @return {JiboLog} Instance of log for chaining.
     */
    warn(): JiboLog  {
        if (!this._enabled || !this._gt(Level.warn)) {
            return this;
        }
        this._minilog.warn.apply(Minilog, arguments);
        return this;
    }

    /**
     * Error log message.
     * @method JiboLog#error
     * @param {*} ..args Arguments for logging
     * @return {JiboLog} Instance of log for chaining.
     */
    error(): JiboLog {
        if (!this._enabled || !this._gt(Level.error)) {
            return this;
        }
        this._minilog.error.apply(Minilog, arguments);
        return this;
    }

    /**
     * Log the error if it is set.
     * @method JiboLog#iferr
     * @param {Error|String} err
     * @param {*} [...args] Additional arguments to log.
     * @return {JiboLog} Instance of log for chaining.
     */
    iferr(err:any, ...args): JiboLog {
        if (err) {
            args.push(err);  // put the error object on the end
            this._minilog.error.apply(Minilog, args);
        }
        return this;
    }

    /**
     * Current name of this log.
     * @name JiboLog#name
     * @type {String}
     */
    get name():string {
        return this._name;
    }
    set name(name:string) {
        if (name && path.isAbsolute(name)) {  
            name = path.basename(name);
        }
        this._name = name;
    }

    /**
     * The minimum level to display, either 'debug', 'info', 'warn', or 'error'.
     * @name JiboLog#minLevel
     * @type {String}
     * @default 'info'
     */
    set minLevel(level:Level) {
        this._minLevel = level;
    }
    get minLevel():Level {
        return this._minLevel;
    }

    /**
     * Log to a file.
     * @method JiboLog#toFile
     * @param {String} [filename] The name of the file to log to.
     * @param {Function} callback Callback when complete.
     */
    toFile(filename?:string, callback?:(err?) => {}) {
        if(process.platform === 'linux' && process.arch === 'arm') {
            if (callback) {
                console.warn("Disabled 'toFile' on robot.");
                callback("Disabled 'toFile' on robot.");
            }
            return;
        }

        // note: we might be logging to multiple files (so can't use this.fileBackend)
        const fileBackend:FileBackend = new FileBackend(filename, this._defaultDir);
        fileBackend.init( () => {
            Minilog.pipe(fileBackend);
            if (callback) {
                callback();
            }
        });
    }

    /**
     * Set the default logging directory.
     * @name JiboLog#defaultDir
     * @type {String}
     */
    set defaultDir(directory:string) {
        this._defaultDir = directory;
    }
    get defaultDir():string {
        return this._defaultDir;
    }

    /**
     * Enable the syslog.
     * @method JiboLog#toSyslog
     */
    toSyslog() {
        if (this._name) {
            JiboLog.syslogBackend.allow(this._name);
        }
    }

    /**
     * Logs are enabled.
     * @name JiboLog#enabled
     * @type {Boolean}
     * @default true
     */
    set enabled(enabled:boolean) {
        this._enabled = enabled;
    }
    get enabled(): boolean {
        return this._enabled;
    }

    /**
     * Handle all uncaught and unhandled exceptions.
     * @name JiboLog#handleAll
     * @type {Boolean}
     * @default false
     */
    set handleAll(handleAll:boolean) {
        if (handleAll) {
            handleUncaughtAndUnhandled();
        }
        else {
            stopHandlingUncaughtAndUnhandled();
        }
        this._handleAll = handleAll;
    }
    get handleAll(): boolean {
        return this._handleAll;
    }

    /**
     * Check to see if the current level is greater than the minLevel.
     * @method JiboLog#_gt
     * @private
     * @return {Boolean} If this level is save to log
     */
    private _gt(level:Level): boolean {
        const levels:Level[] = [
            Level.debug,
            Level.info,
            Level.warn, 
            Level.error
        ];
        return levels.indexOf(level) >= levels.indexOf(this._minLevel);
    }
}

// Minilog.enable();  // this is what you would normally do, it sets up the defaults
// instead we are going to tweak things a bit
// reference http://mixu.net/minilog/filter.html
if (Minilog.defaultFormatter) {
    Minilog
        .pipe(Minilog.suggest)  // suppress messages < 'info' (no debug)
        .pipe(Minilog.defaultFormatter)
        .pipe(Minilog.defaultBackend);
} else {
    Minilog
        .pipe(Minilog.suggest)  // suppress messages < 'info' (no debug)
        .pipe(Minilog.defaultBackend);
}

if (!JiboLog.syslogBackend) {

    // create the syslogBackend singleton
    JiboLog.syslogBackend = new SyslogBackend();

    // always say we will try to pipe to syslogBackend; 
    // the filter is done in the write method
    Minilog.pipe(JiboLog.syslogBackend);
}

export default JiboLog;
